sed -i 's/val ifNotMinusOne = irIfThen(type = pluginContext.irBuiltIns.unitType,/val whileLoop = org.jetbrains.kotlin.ir.expressions.impl.IrWhileLoopImpl(-1, -1, pluginContext.irBuiltIns.unitType, org.jetbrains.kotlin.ir.expressions.IrStatementOrigin.WHILE_LOOP)\n                                whileLoop.condition = irNotEquals(irGet(polledIdx), irInt(-1))\n                                whileLoop.body = /' autumn-compiler-plugin/src/main/kotlin/dev/autumn/compiler/TopologySynthesisTransformer.kt
sed -i 's/condition = irNotEquals(irGet(polledIdx), irInt(-1)),//' autumn-compiler-plugin/src/main/kotlin/dev/autumn/compiler/TopologySynthesisTransformer.kt
sed -i 's/thenPart = irBlock {/irBlock {/' autumn-compiler-plugin/src/main/kotlin/dev/autumn/compiler/TopologySynthesisTransformer.kt
